1032			if report.Status == ExecuteBeadStatusSuccess || report.Status == ExecuteBeadStatusAlreadySatisfied {
1033				terminalPhase = "done"
1034			} else if report.PreserveRef != "" {
1035				terminalPhase = "preserved"
1036			}
1037			// Use the real attempt_id from the report if available.
1038			finalAttemptID := report.AttemptID
1039			if finalAttemptID == "" {
1040				finalAttemptID = provAttemptID
1041			}
1042			phaseSeq++
1043			emitProgress(runtime.ProgressCh, ProgressEvent{
1044				EventID:   "evt-" + randomProgressID(),
1045				AttemptID: finalAttemptID,
1046				WorkerID:  runtime.WorkerID,
1047				ProjectID: runtime.ProjectRoot,
1048				BeadID:    candidate.ID,
1049				Harness:   harness,
1050				Model:     model,
1051				Profile:   profile,
1052				Phase:     terminalPhase,
1053				PhaseSeq:  phaseSeq,
1054				Heartbeat: false,
1055				TS:        now().UTC(),
1056				ElapsedMS: now().Sub(runStart).Milliseconds(),
1057				Message:   report.Detail,
1058			})
1059	
1060			emit("bead.result", map[string]any{
1061				"bead_id":              candidate.ID,
1062				"status":               report.Status,
1063				"detail":               report.Detail,
1064				"session_id":           report.SessionID,
1065				"result_rev":           report.ResultRev,
1066				"base_rev":             report.BaseRev,
1067				"preserve_ref":         report.PreserveRef,
1068				"no_changes_rationale": report.NoChangesRationale,
1069				"duration_ms":          now().Sub(runStart).Milliseconds(),
1070			})
1071	
1072			if runtime.Log != nil {
1073				_, _ = fmt.Fprintf(runtime.Log, "✓ %s → %s\n", candidate.ID, formatLoopResult(report))
1074			}
1075	
1076			if runtime.Once {
1077				return result, nil
1078			}
1079		}
1080	}
