1082	func (w *ExecuteBeadWorker) nextCandidate(attempted map[string]struct{}, labelFilter string) (bead.Bead, bool, error) {
1083		ready, err := w.Store.ReadyExecution()
1084		if err != nil {
1085			return bead.Bead{}, false, err
1086		}
1087		for _, candidate := range ready {
1088			if _, seen := attempted[candidate.ID]; seen {
1089				continue
1090			}
1091			if labelFilter != "" && !HasBeadLabel(candidate.Labels, labelFilter) {
1092				continue
1093			}
1094			return candidate, true, nil
1095		}
1096		return bead.Bead{}, false, nil
1097	}
